#[tokio::test]
async fn test_rag_pipeline_e2e() {
    // Setup: LiteStore + MockEngine + VectorRetriever + StructuredAugmenter
    let dir = tempfile::tempdir().unwrap();
    let config = corvia_common::config::CorviaConfig::default();

    let store = Arc::new(corvia_kernel::lite_store::LiteStore::open(dir.path(), 3).unwrap())
        as Arc<dyn corvia_kernel::traits::QueryableStore>;
    store.init_schema().await.unwrap();

    // MockEngine for deterministic embedding
    let engine = Arc::new(MockEngine) as Arc<dyn corvia_kernel::traits::InferenceEngine>;

    // Insert test knowledge
    let mut idx = 0_usize;
    let mut next_emb = || { idx += 1; vec![1.0, idx as f32 * 0.001, 0.0] };

    for i in 0..10 {
        let mut e = corvia_common::types::KnowledgeEntry::new(
            format!("Knowledge about topic {i}"), "test-scope".into(), "v1".into(),
        ).with_embedding(next_emb());
        e.entry_status = corvia_common::agent_types::EntryStatus::Merged;
